// // This module implements a 2-to-1 multiplexer where input A is selected when S is 1
module mux_2to1(
    input A,
    input B,
    input S,
    output reg Y
);

    always @(*) begin
        if(S == 0) begin
            Y = A;
        end
        else begin
            Y = B;
        end
    end

endmodule
